// Generator for docs/TEST-DISPLAY-MAP.md.
//
// Reads every source-of-truth field directly from src/ and runs the 22-fixture
// batch to capture per-test, per-fixture flag levels. The output doc is
// regenerated by this script alone — never hand-edited.
//
// Run:  node scripts/build-test-display-map.mjs
//
// Sources:
//   ENGINE NAME   — TEST_MECHANISM keys (src/constants/mechanisms.js)
//   DISPLAY NAME  — DISPLAY_NAMES (same file)
//   UI CLUSTER    — MECHANISMS[TEST_MECHANISM[name]].label
//                   (the authoritative §3 grouping — ReportView.jsx threads
//                    `label={MECHANISMS[mk]?.label}` to ForensicsCategoryBlock
//                    based on TEST_MECHANISM[r.name])
//   FLAGGED-ON    — batch result.flag per fixture, captured by re-running the
//                   exact pipeline validate-batch.mjs uses (extractAnalysisInputs
//                   → runFullAnalysis)

import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';
import { execSync } from 'child_process';

globalThis.requestAnimationFrame = (cb) => setTimeout(cb, 0);

const Papa = await import('papaparse');
const { extractAnalysisInputs, runFullAnalysis } = await import('../src/analysis/engine.js');
const { detectVST } = await import('../src/stats/vst.js');
const { inferRoles } = await import('../src/import/roles.js');
const { forwardFill, preprocessRaw, detectHeaderRows } = await import('../src/import/parser.js');
const { detectLongFormat } = await import('../src/import/longFormat.js');
const { suggestRowSemantics } = await import('../src/import/rowSemantics.js');
const {
  DISPLAY_NAMES,
  TEST_MECHANISM,
  MECHANISMS,
  MECHANISM_ORDER,
} = await import('../src/constants/mechanisms.js');

const FIXTURES_DIR = 'test/fixtures';

// Same EXPECTED list as test/validate-batch.mjs (severity not consumed here —
// only the assay routing and fixture set). Kept in this order so the doc
// columns read DS01..DS22 left-to-right.
const FIXTURES = [
  ['01-densitometry-clean.csv',                  'DS01',  'densitometry'],
  ['02-densitometry-fabricated.csv',             'DS02',  'densitometry'],
  ['03-qpcr-clean.csv',                          'DS03',  'qpcr'],
  ['04-qpcr-fabricated.csv',                     'DS04',  'qpcr'],
  ['05-cellcount-clean.csv',                     'DS05',  'cell_count'],
  ['06-cellcount-fabricated.csv',                'DS06',  'cell_count'],
  ['07-elisa-clean.csv',                         'DS07',  'elisa'],
  ['08-elisa-fabricated.csv',                    'DS08',  'elisa'],
  ['09-proteomics-clean.csv',                    'DS09',  'proteomics'],
  ['10-proteomics-fabricated.csv',               'DS10',  'proteomics'],
  ['11-rnaseq-multicondition.csv',               'DS11',  'genomics'],
  ['12a-uniform-mixture-clean.csv',              'DS12a', 'general'],
  ['12b-uniform-mixture-fabricated.csv',         'DS12b', 'general'],
  ['13-vfstest-cellcountest.csv',                'DS13',  'cell_count'],
  ['14-crctest-survey.csv',                      'DS14',  'survey'],
  ['15-missing-carlisle.csv',                    'DS15',  'general'],
  ['16-densitometry-carlisle-overbalanced.csv',  'DS16',  'densitometry'],
  ['17-densitometry-carlisle-clean.csv',         'DS17',  'densitometry'],
  ['19-inheritance-fabricated.csv',              'DS19',  'general'],
  ['20-bimodal-fab.csv',                         'DS20',  'general'],
  ['21-localised-ar.csv',                        'DS21',  'general'],
  ['22-covariance-block.csv',                    'DS22',  'general'],
];

// Map engine flag → compact display token (HIGH/MOD/LOW/N-A). Only HIGH and
// MOD enter the FLAGGED-ON column; LOW/N-A surface as "none — latent" when no
// fixture flagged the test above LOW.
const FLAG_SHORT = { HIGH: 'HIGH', MODERATE: 'MOD' };

const allTests = Object.keys(TEST_MECHANISM);
// flagsByTest[name][fixtureKey] = 'HIGH' | 'MODERATE' | 'LOW' | 'N/A'
const flagsByTest = Object.fromEntries(allTests.map(t => [t, {}]));

for (const [file, key, assay] of FIXTURES) {
  process.stderr.write(`  ${key}…`);
  const csv = readFileSync(join(FIXTURES_DIR, file), 'utf-8');
  const parsed = Papa.default.parse(csv, { skipEmptyLines: true });
  let raw = parsed.data;

  const pp = preprocessRaw(raw);
  raw = pp.rows;
  const headerRows = detectHeaderRows(raw);
  let condPerCol = null;
  if (headerRows >= 2) condPerCol = forwardFill(raw[0]);
  const headers = raw[headerRows - 1];
  const data = raw.slice(headerRows);
  const roles = inferRoles(data, headers, condPerCol);

  const { matrix, rawMatrix, condCtx } = extractAnalysisInputs({
    data, roles, condPerCol, zeroAsMissing: false,
  });
  const vst = detectVST(matrix, assay);
  const dataType = assay === 'survey' ? 'survey'
                 : (assay === 'cell_count' ? 'count' : 'continuous');
  const lfDet = detectLongFormat(headers, data);
  const rsSuggestion = suggestRowSemantics({ assay, longFormatDetected: !!lfDet });
  const rowSemantics = rsSuggestion.value || 'ordered';

  const results = await runFullAnalysis(
    matrix, rawMatrix, condCtx, assay, null, vst, {}, dataType, rowSemantics,
  );

  for (const r of results) {
    if (!(r.name in flagsByTest)) continue; // ignore engine-internal pseudo-results
    flagsByTest[r.name][key] = r.flag;
  }
  process.stderr.write(' ok\n');
}

// ── Build the markdown ──
const sha = execSync('git rev-parse HEAD', { encoding: 'utf-8' }).trim();
const shortSha = sha.slice(0, 7);
const branch = execSync('git rev-parse --abbrev-ref HEAD', { encoding: 'utf-8' }).trim();
const now = new Date().toISOString().replace('T', ' ').slice(0, 19) + 'Z';

// Sort test rows: cluster order (MECHANISM_ORDER) → display name asc.
const rows = allTests.map(name => {
  const mk = TEST_MECHANISM[name];
  return {
    name,
    display: DISPLAY_NAMES[name] || name,
    clusterKey: mk,
    clusterLabel: MECHANISMS[mk]?.label || mk,
  };
}).sort((a, b) => {
  const ai = MECHANISM_ORDER.indexOf(a.clusterKey);
  const bi = MECHANISM_ORDER.indexOf(b.clusterKey);
  if (ai !== bi) return ai - bi;
  return a.display.localeCompare(b.display);
});

// Build FLAGGED-ON cell per row.
function flaggedCell(name) {
  const entries = FIXTURES
    .map(([_, key]) => [key, flagsByTest[name][key]])
    .filter(([_, flag]) => flag === 'HIGH' || flag === 'MODERATE')
    .map(([key, flag]) => `${key} ${FLAG_SHORT[flag]}`);
  if (entries.length === 0) return 'none — latent';
  return entries.join(', ');
}

const lines = [];
lines.push('# Test → display map');
lines.push('');
lines.push('**GENERATED — DO NOT HAND-EDIT** — regenerate via');
lines.push('`node scripts/build-test-display-map.mjs`');
lines.push('');
lines.push(`- Generated: ${now}`);
lines.push(`- Commit:    \`${shortSha}\` (\`${sha}\`)`);
lines.push(`- Branch:    \`${branch}\``);
lines.push(`- Batch:     \`node test/validate-batch.mjs\` (this script reproduces the validate-batch pipeline against ${FIXTURES.length} fixtures on the branch above)`);
lines.push('');
lines.push('## What this is');
lines.push('');
lines.push('Single source-of-truth reference mapping every active engine test to:');
lines.push('');
lines.push('1. its `result.name` (engine identifier, the key shared by `MINIPLOT_REGISTRY`, `TEMPLATE_MAP`, and the seven dispatch maps in `src/constants/mechanisms.js`);');
lines.push('2. its user-facing display name from `DISPLAY_NAMES` (`src/constants/mechanisms.js`);');
lines.push('3. the **UI cluster** it renders under in §3 — the `MECHANISMS[k].label` corresponding to `TEST_MECHANISM[name]`. `ReportView.jsx` threads this label through to `ForensicsCategoryBlock` for §3 grouping; it IS the on-screen cluster heading.');
lines.push('4. the fixtures it fired on (HIGH or MOD), taken from the engine\'s `result.flag` output across the 22-fixture batch. Tests that returned only LOW / N/A across every fixture are listed as "none — latent".');
lines.push('');
lines.push('Replaces methodology-prose reasoning about display behaviour with empirical batch output.');
lines.push('');
lines.push('## UI cluster vs working-cluster vocabulary');
lines.push('');
lines.push('The §3 UI grouping uses the five `MECHANISMS` labels: **Copy, paste, edit** / **Unusual digits** / **Distribution shapes** / **Cross-replicate comparisons** / **Cross-condition comparisons** (`MECHANISM_ORDER`). This map\'s "Cluster" column carries that vocabulary because that is what the user reads on screen.');
lines.push('');
lines.push('The working-cluster names used in `docs/shared/TESTCARD-FINDINGS.md` for A2 chrome passes — _clone-duplication_, _cross-condition consistency_, _distribution shape_, _spread / heteroscedasticity_, _ordering / sequence_, _cell-level_ — are a finer vocabulary that cross-cuts the UI clusters. The correspondences are not 1:1:');
lines.push('');
lines.push('| Working cluster (TESTCARD-FINDINGS)        | UI clusters it touches                                   |');
lines.push('|--------------------------------------------|----------------------------------------------------------|');
lines.push('| clone-duplication                          | Copy, paste, edit                                        |');
lines.push('| cross-condition consistency                | Copy, paste, edit (RSC); Cross-condition comparisons (CCC) |');
lines.push('| distribution shape                         | Unusual digits; Distribution shapes                      |');
lines.push('| spread / heteroscedasticity                | Cross-replicate comparisons (IRC, Kurtosis, …)           |');
lines.push('| ordering / sequence                        | Cross-replicate comparisons (Autocorr, Runs, Row-Mean Runs, LOESS) |');
lines.push('| cell-level                                 | Cross-replicate comparisons (Mahalanobis, Within-Row Variance) |');
lines.push('');
lines.push('Flag this mismatch — it is real and worth carrying. The map below renders the UI cluster only.');
lines.push('');
lines.push('## The map');
lines.push('');
lines.push('Sorted by `MECHANISM_ORDER` (copied → digits → shapes → replicate → group), then by display name within cluster.');
lines.push('');
lines.push('| Display name | Engine name | Cluster (§3 UI) | Flagged on (HIGH / MOD) |');
lines.push('|---|---|---|---|');
for (const row of rows) {
  lines.push(`| ${row.display} | ${row.name} | ${row.clusterLabel} | ${flaggedCell(row.name)} |`);
}
lines.push('');
lines.push('---');
lines.push('');
lines.push(`Fixtures covered (${FIXTURES.length}): ${FIXTURES.map(f => f[1]).join(', ')}.`);
lines.push('');

const out = lines.join('\n');
const outPath = 'docs/TEST-DISPLAY-MAP.md';
writeFileSync(outPath, out);
process.stderr.write(`\nWrote ${outPath} — ${rows.length} tests, ${FIXTURES.length} fixtures.\n`);
